#include <iostream>

void swapNumbers(int* ptr1, int* ptr2);

int main() {
    int x_val = 5;
    int y_val = 10;
    std::cout << "Before swap: x = " << x_val << ", y = " << y_val << std::endl;
    swapNumbers(&x_val, &y_val);
    std::cout << "After swap: x = " << x_val << ", y = " << y_val << std::endl;

    int p_val = 100;
    int q_val = 200;
    std::cout << "Before swap: p = " << p_val << ", q = " << q_val << std::endl;
    swapNumbers(&p_val, &q_val);
    std::cout << "After swap: p = " << p_val << ", q = " << q_val << std::endl;
    return 0;
}
